/**
 * Unit Tests: Share Link Service
 * Testa criação, resolução e revogação de links compartilháveis
 * @see src/lib/share/share-link-service.ts
 */

import { ShareLinkError } from '@/lib/share/share-link-service';

// Mock Prisma before importing service functions
// Use jest.fn() inline to avoid hoisting issues
jest.mock('@/lib/prisma', () => ({
  prisma: {
    share_links: {
      create: jest.fn(),
      findUnique: jest.fn(),
      findFirst: jest.fn(),
      findMany: jest.fn(),
      update: jest.fn(),
    },
    projects: {
      findFirst: jest.fn(),
      findUnique: jest.fn(),
    },
    render_jobs: {
      findFirst: jest.fn(),
    },
  },
}));

jest.mock('@/lib/logger', () => ({
  Logger: jest.fn().mockImplementation(() => ({
    info: jest.fn(),
    warn: jest.fn(),
    error: jest.fn(),
    debug: jest.fn(),
  })),
  logger: {
    info: jest.fn(),
    warn: jest.fn(),
    error: jest.fn(),
    debug: jest.fn(),
  },
}));

// Import after mocks — get the mocked prisma
import { createShareLink, resolveShareLink, listShareLinks, revokeShareLink } from '@/lib/share/share-link-service';
import { prisma } from '@/lib/prisma';

// Type the mocked prisma for cleaner assertions
const mockPrisma = prisma as unknown as {
  share_links: {
    create: jest.Mock;
    findUnique: jest.Mock;
    findFirst: jest.Mock;
    findMany: jest.Mock;
    update: jest.Mock;
  };
  projects: {
    findFirst: jest.Mock;
    findUnique: jest.Mock;
  };
  render_jobs: {
    findFirst: jest.Mock;
  };
};

describe('ShareLinkService', () => {
  beforeEach(() => {
    jest.clearAllMocks();
    process.env.NEXT_PUBLIC_APP_URL = 'https://example.com';
    process.env.SHARE_LINK_SECRET = 'test-secret-key-for-testing';
  });

  describe('ShareLinkError', () => {
    it('should create error with code', () => {
      const error = new ShareLinkError('Test error', 'LINK_NOT_FOUND');
      expect(error.message).toBe('Test error');
      expect(error.code).toBe('LINK_NOT_FOUND');
      expect(error.name).toBe('ShareLinkError');
    });

    it('should be instanceof Error', () => {
      const error = new ShareLinkError('test', 'LINK_EXPIRED');
      expect(error).toBeInstanceOf(Error);
    });

    it('should support all error codes', () => {
      const codes = [
        'PROJECT_NOT_FOUND',
        'LINK_NOT_FOUND',
        'LINK_EXPIRED',
        'LINK_DISABLED',
        'MAX_VIEWS_REACHED',
        'PASSWORD_REQUIRED',
        'INVALID_PASSWORD',
      ] as const;

      codes.forEach((code) => {
        const error = new ShareLinkError(`Error: ${code}`, code);
        expect(error.code).toBe(code);
      });
    });
  });

  describe('createShareLink', () => {
    it('should create a share link with default options', async () => {
      mockPrisma.projects.findFirst.mockResolvedValue({ id: 'proj-1' });
      mockPrisma.share_links.create.mockResolvedValue({
        id: 'link-1',
        token: 'abc123',
        expiresAt: new Date('2030-01-01'),
        maxViews: null,
        isActive: true,
      });

      const result = await createShareLink({
        projectId: 'proj-1',
        userId: 'user-1',
      });

      expect(result.id).toBe('link-1');
      expect(result.url).toContain('https://example.com/share/');
      expect(result.isActive).toBe(true);
      expect(result.maxViews).toBeNull();

      // Should have called projects.findFirst to verify ownership
      expect(mockPrisma.projects.findFirst).toHaveBeenCalledWith({
        where: { id: 'proj-1', userId: 'user-1' },
        select: { id: true },
      });
    });

    it('should throw PROJECT_NOT_FOUND when project does not belong to user', async () => {
      mockPrisma.projects.findFirst.mockResolvedValue(null);

      await expect(createShareLink({
        projectId: 'proj-1',
        userId: 'user-1',
      })).rejects.toThrow(ShareLinkError);

      try {
        mockPrisma.projects.findFirst.mockResolvedValue(null);
        await createShareLink({ projectId: 'proj-1', userId: 'user-1' });
      } catch (e) {
        expect((e as ShareLinkError).code).toBe('PROJECT_NOT_FOUND');
      }
    });

    it('should hash password when provided', async () => {
      mockPrisma.projects.findFirst.mockResolvedValue({ id: 'proj-1' });
      mockPrisma.share_links.create.mockResolvedValue({
        id: 'link-2',
        token: 'def456',
        expiresAt: new Date('2030-01-01'),
        maxViews: null,
        isActive: true,
      });

      await createShareLink({
        projectId: 'proj-1',
        userId: 'user-1',
        password: 'mypassword',
      });

      // The password field in the create call should be a hash, not the plaintext
      const createCall = mockPrisma.share_links.create.mock.calls[0][0];
      expect(createCall.data.password).not.toBe('mypassword');
      expect(createCall.data.password).toHaveLength(64); // SHA-256 hex = 64 chars
    });

    it('should respect custom expiration hours', async () => {
      mockPrisma.projects.findFirst.mockResolvedValue({ id: 'proj-1' });
      mockPrisma.share_links.create.mockImplementation(({ data }: { data: Record<string, unknown> }) => {
        return Promise.resolve({
          id: 'link-3',
          token: data.token,
          expiresAt: data.expiresAt,
          maxViews: data.maxViews,
          isActive: true,
        });
      });

      const before = Date.now();
      await createShareLink({
        projectId: 'proj-1',
        userId: 'user-1',
        expirationHours: 24,
      });

      const createCall = mockPrisma.share_links.create.mock.calls[0][0];
      const expiresAt = new Date(createCall.data.expiresAt).getTime();
      const expectedMs = 24 * 60 * 60 * 1000;

      // Should expire approximately 24 hours from now
      expect(expiresAt - before).toBeGreaterThan(expectedMs - 1000);
      expect(expiresAt - before).toBeLessThan(expectedMs + 1000);
    });

    it('should support maxViews setting', async () => {
      mockPrisma.projects.findFirst.mockResolvedValue({ id: 'proj-1' });
      mockPrisma.share_links.create.mockImplementation(({ data }: { data: Record<string, unknown> }) => {
        return Promise.resolve({
          id: 'link-4',
          token: data.token,
          expiresAt: data.expiresAt,
          maxViews: data.maxViews,
          isActive: true,
        });
      });

      await createShareLink({
        projectId: 'proj-1',
        userId: 'user-1',
        maxViews: 10,
      });

      const createCall = mockPrisma.share_links.create.mock.calls[0][0];
      expect(createCall.data.maxViews).toBe(10);
    });
  });

  describe('resolveShareLink', () => {
    const mockActiveLink = {
      id: 'link-1',
      token: 'valid-token',
      projectId: 'proj-1',
      userId: 'user-1',
      resourceType: 'video',
      resourceId: null,
      isActive: true,
      expiresAt: new Date('2099-01-01'),
      maxViews: null,
      viewCount: 0,
      password: null,
      metadata: {},
    };

    it('should resolve a valid share link', async () => {
      mockPrisma.share_links.findUnique.mockResolvedValue(mockActiveLink);
      mockPrisma.share_links.update.mockResolvedValue({});
      mockPrisma.projects.findUnique.mockResolvedValue({
        id: 'proj-1',
        name: 'Test Project',
        thumbnailUrl: null,
        previewUrl: null,
      });
      mockPrisma.render_jobs.findFirst.mockResolvedValue({
        id: 'job-1',
        outputUrl: 'https://example.com/video.mp4',
        status: 'completed',
      });

      const result = await resolveShareLink('valid-token');

      expect(result.projectId).toBe('proj-1');
      expect(result.userId).toBe('user-1');
      expect(result.project).not.toBeNull();
      expect(result.renderJob).not.toBeNull();

      // Should increment view count
      expect(mockPrisma.share_links.update).toHaveBeenCalledWith({
        where: { id: 'link-1' },
        data: { viewCount: { increment: 1 } },
      });
    });

    it('should throw LINK_NOT_FOUND for invalid token', async () => {
      mockPrisma.share_links.findUnique.mockResolvedValue(null);

      try {
        await resolveShareLink('invalid-token');
        fail('Should have thrown');
      } catch (e) {
        expect(e).toBeInstanceOf(ShareLinkError);
        expect((e as ShareLinkError).code).toBe('LINK_NOT_FOUND');
      }
    });

    it('should throw LINK_DISABLED for inactive link', async () => {
      mockPrisma.share_links.findUnique.mockResolvedValue({
        ...mockActiveLink,
        isActive: false,
      });

      try {
        await resolveShareLink('valid-token');
        fail('Should have thrown');
      } catch (e) {
        expect((e as ShareLinkError).code).toBe('LINK_DISABLED');
      }
    });

    it('should throw LINK_EXPIRED for expired link', async () => {
      mockPrisma.share_links.findUnique.mockResolvedValue({
        ...mockActiveLink,
        expiresAt: new Date('2000-01-01'),
      });
      mockPrisma.share_links.update.mockResolvedValue({});

      try {
        await resolveShareLink('valid-token');
        fail('Should have thrown');
      } catch (e) {
        expect((e as ShareLinkError).code).toBe('LINK_EXPIRED');
        // Should auto-deactivate
        expect(mockPrisma.share_links.update).toHaveBeenCalledWith({
          where: { id: 'link-1' },
          data: { isActive: false },
        });
      }
    });

    it('should throw MAX_VIEWS_REACHED when limit exceeded', async () => {
      mockPrisma.share_links.findUnique.mockResolvedValue({
        ...mockActiveLink,
        maxViews: 5,
        viewCount: 5,
      });
      mockPrisma.share_links.update.mockResolvedValue({});

      try {
        await resolveShareLink('valid-token');
        fail('Should have thrown');
      } catch (e) {
        expect((e as ShareLinkError).code).toBe('MAX_VIEWS_REACHED');
      }
    });

    it('should throw PASSWORD_REQUIRED when link has password but none provided', async () => {
      mockPrisma.share_links.findUnique.mockResolvedValue({
        ...mockActiveLink,
        password: 'some-hash',
      });

      try {
        await resolveShareLink('valid-token');
        fail('Should have thrown');
      } catch (e) {
        expect((e as ShareLinkError).code).toBe('PASSWORD_REQUIRED');
      }
    });
  });

  describe('listShareLinks', () => {
    it('should list links for a user', async () => {
      mockPrisma.share_links.findMany.mockResolvedValue([
        {
          id: 'link-1',
          token: 'token-1',
          expiresAt: new Date('2099-01-01'),
          maxViews: null,
          isActive: true,
        },
        {
          id: 'link-2',
          token: 'token-2',
          expiresAt: new Date('2000-01-01'),
          maxViews: 10,
          isActive: true,
        },
      ]);

      const links = await listShareLinks('user-1');

      expect(links).toHaveLength(2);
      expect(links[0].url).toContain('/share/token-1');
      // Second link is expired so isActive should be false
      expect(links[1].isActive).toBe(false);
    });

    it('should filter by projectId when provided', async () => {
      mockPrisma.share_links.findMany.mockResolvedValue([]);

      await listShareLinks('user-1', 'proj-1');

      expect(mockPrisma.share_links.findMany).toHaveBeenCalledWith(
        expect.objectContaining({
          where: { userId: 'user-1', projectId: 'proj-1' },
        })
      );
    });
  });

  describe('revokeShareLink', () => {
    it('should revoke an existing link', async () => {
      mockPrisma.share_links.findFirst.mockResolvedValue({ id: 'link-1', userId: 'user-1' });
      mockPrisma.share_links.update.mockResolvedValue({});

      await expect(revokeShareLink('link-1', 'user-1')).resolves.not.toThrow();

      expect(mockPrisma.share_links.update).toHaveBeenCalledWith({
        where: { id: 'link-1' },
        data: { isActive: false },
      });
    });

    it('should throw LINK_NOT_FOUND for non-existent link', async () => {
      mockPrisma.share_links.findFirst.mockResolvedValue(null);

      try {
        await revokeShareLink('nonexistent', 'user-1');
        fail('Should have thrown');
      } catch (e) {
        expect((e as ShareLinkError).code).toBe('LINK_NOT_FOUND');
      }
    });

    it('should throw LINK_NOT_FOUND when link belongs to different user', async () => {
      mockPrisma.share_links.findFirst.mockResolvedValue(null); // findFirst with userId filter returns null

      try {
        await revokeShareLink('link-1', 'wrong-user');
        fail('Should have thrown');
      } catch (e) {
        expect((e as ShareLinkError).code).toBe('LINK_NOT_FOUND');
      }
    });
  });
});
